# Value-based guard thresholds for the robust large-panel route. CholeskyQR-HR is
# only numerically valid for well-conditioned panels; ill-conditioned panels fall
# back to the incumbent geqrf path. Both thresholds sit far above what the cond=1
# dense benchmark panels produce (measured diag_ratio<=2.1, rdiag_ratio<=1.7), so
# the dense large speedup is preserved while any ill-conditioned panel (non-PD or
# high column-condition) is routed to geqrf.
LARGE_CHOLQR_DIAG_RATIO_MAX = 1.0e3
LARGE_CHOLQR_RDIAG_RATIO_MAX = 16.0
# CholeskyQR-HR reconstruction routes its two triangular solves (Q1 = A R^-1 and
# the dorhr tail solve) by batch. The custom one-CTA-per-matrix upper-tri inverse
# is latency-bound at ~fixed cost regardless of batch, so it beats the per-matrix-
# serialised triangular solve only once the batch is large enough to amortise that
# fixed cost: measured cross-over is ~batch 3-4 (custom ~3x faster at batch 8,
# ~equal-to-slower at batch 2). Panels with fewer than this many matrices keep the
# library solve; this is a pure performance route (both paths are numerically
# identical to ~1e-7) and depends only on the public batch size.
LARGE_CUSTOM_RECON_MIN_BATCH = 4
N512_FIRST16_PANEL_MAXNREG = 128
N1024_DENSE_PROJECTED_PREFIX = 924
N1024_N2048_PROJECTED_PREFIX = 956
N1024_N4096_PROJECTED_PREFIX = 928
N1024_N4096_BATCH_GT1_PROJECTED_PREFIX = 732
N1024_EMIT_YGRAM_APPLY_START = 736
N512_ROUTE_DENSE = 0
N512_ROUTE_CLUSTERED = 1
N512_ROUTE_RANKDEF = 2
N512_ROUTE_MIXED = 3
# Columns cast speculatively before the n512 route host-read. Sized to cover the
# ~66us detector host-sync with real cast bandwidth (and to exactly match the
# clustered route's 256-column live prefix) so the cast is needed work for the
# bulk-FP16 routes and only an overlap-sized cost for the mixed fallback.
N512_SPEC_CAST_COLS = 256
N1024_TLX_SECOND16_START = 0
N1024_TLX_SECOND16_WARP_CAP = 8

def panel8_warps(active_rows_pow2: int) -> int:
    """Cap n1024 panel8 chunks below the incumbent full-height warp count."""
    return min(panel_warps(active_rows_pow2), 8)

def offpanel_packed_copy_tiles(n: int) -> int:
    """Return the packed tile count for 16x64 off-panel upper-copy tiles."""
    col_tiles = triton.cdiv(n, COPY_COL_BLOCK)
    return 2 * col_tiles * col_tiles

def offpanel_wide_copy_tiles(n: int) -> int:
    """Return the packed tile count for 16x128 off-panel upper-copy tiles."""
    col_tiles = triton.cdiv(n, COPY_WIDE_COL_BLOCK)
    return 4 * col_tiles * col_tiles + 2 * col_tiles


def suffix_packed_copy_tiles(suffix_extent: int) -> int:
    """Return packed tile count for 16x64 upper-triangular suffix-copy tiles."""
    col_tiles = triton.cdiv(suffix_extent, COPY_COL_BLOCK)
    return 2 * col_tiles * col_tiles + 2 * col_tiles


def launch_factor_second16_n1024_panel(
    h16: torch.Tensor,
    h: torch.Tensor,
    tau: torch.Tensor,
    k: int,
    n: int,
    mp: int,
    batch: int,
) -> None:
    """Launch the TLX replacement for the n1024 second16 panel step."""
    if TLX_AVAILABLE and k >= N1024_TLX_SECOND16_START:
        tlx_warps = min(panel8_warps(mp), N1024_TLX_SECOND16_WARP_CAP)
        factor_second16_split_tiles_n1024_tlx_kernel[(batch,)](
            h16, h, tau, k, n, mp, num_warps=tlx_warps, num_stages=1
        )
        return
    factor_second16_split_tiles_n1024_fp16state_kernel[(batch,)](
        h16, h, tau, k, n, mp, num_warps=panel8_warps(mp), num_stages=1
    )


def householder_triton_qr32(data: torch.Tensor) -> output_t:
    """Factor n32 matrices with one compact-Householder Triton launch."""
    h = torch.empty_like(data)
    tau = torch.empty((data.shape[0], 32), device=data.device, dtype=torch.float32)
    factor_qr32_householder_kernel[(data.shape[0],)](
        data,
        h,
        tau,
        num_warps=1,
        num_stages=1,
    )
    return h, tau

def householder_blocked_wy_n512_fp16resident_gram(
    data: torch.Tensor, col_stop: int = 512, h16: torch.Tensor | None = None
) -> output_t:
    """Factor n512 resident-FP16 panels with compact-WY updates."""
    h = torch.empty_like(data)
    batch, n, _ = h.shape
    if h16 is None:
        # No hoisted cast: build the resident FP16 state locally.
        if col_stop < n:
            h16 = torch.empty((batch, n, n), device=h.device, dtype=torch.float16)
            copy_fp32_to_fp16_prefix_kernel[
                (batch, triton.cdiv(n, COPY_ROW_BLOCK), triton.cdiv(col_stop, INIT_COPY_COL_BLOCK))
            ](
                data,
                h16,
                n,
                col_stop,
                COPY_ROW_BLOCK,
                INIT_COPY_COL_BLOCK,
                num_warps=4,
                num_stages=4,
            )
        else:
            h16 = data.to(torch.float16)
    # When the caller hoists the full data.to(fp16) cast across the detector
    # host-sync, it is passed in here. The panel loop and trailing apply only
    # touch columns < col_stop, so a full cast is bit-identical to the
    # prefix-only copy for the structured (clustered/rankdef) routes; the unused
    # suffix columns are zeroed in the final upper-copy regardless.
    tau = torch.empty((batch, n), device=h.device, dtype=torch.float32)
    use_factor_emit_ygram = batch == 640
    if use_factor_emit_ygram:
        y_scratch = torch.empty((batch, n, PANEL_COLS), device=h.device, dtype=torch.float16)
        gram_scratch = torch.empty((batch, PANEL_COLS, PANEL_COLS), device=h.device, dtype=torch.float16)
    else:
        y_scratch = None
        gram_scratch = None
    apply_panel = (
        apply_block_reflector_n512_fp16resident_fused_ygram
        if batch == 640
        else apply_block_reflector_n512_fp16resident_gram
    )
    for k in range(0, col_stop, PANEL_COLS):
        # Factor the 32-column panel as two resident-FP16 16-column panel launches.
        mp = ceil_pow2(n - k)
        factor_panel16_apply_next16_n512_fp16state_kernel[(batch,)](
            h16,
            h,
            tau,
            k,
            n,
            mp,
            num_warps=panel_warps(mp),
            num_stages=1,
            maxnreg=N512_FIRST16_PANEL_MAXNREG,
        )
        k_second = k + PANEL_COLS_N512
        mp_second = ceil_pow2(n - k_second)
        if use_factor_emit_ygram and k + PANEL_COLS < col_stop:
            factor_panel_n512_fp16state_emit_ygram_kernel[(batch,)](
                h16,
                h,
                tau,
                y_scratch,
                gram_scratch,
                k,
                k_second,
                n,
                mp_second,
                PANEL_COLS_N512,
                128,
                num_warps=4,
                num_stages=1,
                maxnreg=160,
            )
            if k >= 448:
                apply_block_reflector_n512_fp16resident_prebuilt_tsolve_fused(
                    h16, y_scratch, gram_scratch, k, col_stop
                )
            else:
                apply_block_reflector_n512_fp16resident_prebuilt_ygram(
                    h16, tau, y_scratch, gram_scratch, k, col_stop
                )
        else:
            factor_panel_n512_fp16state_kernel[(batch,)](
                h16,
                h,
                tau,
                k_second,
                n,
                mp_second,
                PANEL_COLS_N512,
                num_warps=panel_warps(mp_second),
                num_stages=1,
            )
            apply_panel(h16, tau, k, col_stop)
    if col_stop < n:
        zero_suffix_columns_and_tau_kernel[
            (batch, triton.cdiv(n, COPY_ROW_BLOCK), triton.cdiv(n - col_stop, COPY_COL_BLOCK))
        ](
            h,
            tau,
            n,
            col_stop,
            COPY_ROW_BLOCK,
            COPY_COL_BLOCK,
            num_warps=4,
            num_stages=4,
        )
        copy_upper_from_fp16_offpanel_packed_kernel[(batch, offpanel_packed_copy_tiles(col_stop))](
            h16,
            h,
            n,
            COPY_ROW_BLOCK,
            COPY_COL_BLOCK,
            num_warps=4,
            num_stages=4,
        )
    else:
        copy_upper_from_fp16_offpanel_wide_kernel[(batch, offpanel_wide_copy_tiles(n))](
            h16,
            h,
            n,
            COPY_ROW_BLOCK,
            COPY_WIDE_COL_BLOCK,
            num_warps=4,
            num_stages=4,
        )
    return h, tau

def householder_blocked_wy_mid_fp16resident_gram(data: torch.Tensor) -> output_t:
    """Use the resident FP16 compact apply path for homogeneous n176/n352."""

    h = torch.empty_like(data)
    h16 = data.to(torch.float16)
    batch, n, _ = h.shape
    tau = torch.empty((batch, n), device=h.device, dtype=torch.float32)
    use_factor_emit_ygram = n == 352
    if use_factor_emit_ygram:
        y_scratch = torch.empty((batch, n, PANEL_COLS), device=h.device, dtype=torch.float16)
        gram_scratch = torch.empty((batch, PANEL_COLS, PANEL_COLS), device=h.device, dtype=torch.float16)
    else:
        y_scratch = None
        gram_scratch = None
    for k in range(0, n, PANEL_COLS):
        b = min(PANEL_COLS, n - k)
        if b == PANEL_COLS:
            # Full panels use the same split resident-FP16 factor path as n512.
            mp = ceil_pow2(n - k)
            factor_panel16_apply_next16_n512_fp16state_kernel[(batch,)](
                h16,
                h,
                tau,
                k,
                n,
                mp,
                num_warps=panel_warps(mp),
                num_stages=1,
            )
            k_second = k + PANEL_COLS_N512
            mp_second = ceil_pow2(n - k_second)
            if use_factor_emit_ygram and k + PANEL_COLS < n:
                factor_panel_n512_fp16state_emit_ygram_kernel[(batch,)](
                    h16,
                    h,
                    tau,
                    y_scratch,
                    gram_scratch,
                    k,
                    k_second,
                    n,
                    mp_second,
                    PANEL_COLS_N512,
                    64,
                    num_warps=4,
                    num_stages=1,
                    maxnreg=160,
                )
                if k + 2 * PANEL_COLS >= n:
                    apply_block_reflector_n512_fp16resident_prebuilt_tsolve_fused(
                        h16, y_scratch, gram_scratch, k, n
                    )
                else:
                    apply_block_reflector_n512_fp16resident_prebuilt_ygram(
                        h16, tau, y_scratch, gram_scratch, k, n
                    )
            else:
                factor_panel_n512_fp16state_kernel[(batch,)](
                    h16,
                    h,
                    tau,
                    k_second,
                    n,
                    mp_second,
                    PANEL_COLS_N512,
                    num_warps=panel_warps(mp_second),
                    num_stages=1,
                )
                apply_block_reflector_n512_fp16resident_gram(h16, tau, k, n)
        else:
            # n176 ends with a valid 16-column compact panel and no trailing
            # columns. The split32 helper would read past the matrix width here.
            mp = ceil_pow2(n - k)
            factor_panel_n512_fp16state_kernel[(batch,)](
                h16,
                h,
                tau,
                k,
                n,
                mp,
                b,
                num_warps=panel_warps(mp),
                num_stages=1,
            )
    copy_upper_from_fp16_offpanel_packed_kernel[(batch, offpanel_packed_copy_tiles(n))](
        h16,
        h,
        n,
        COPY_ROW_BLOCK,
        COPY_COL_BLOCK,
        num_warps=4,
        num_stages=4,
    )
    return h, tau

def householder_blocked_wy_mid_fp16resident_gram_from_h16(h16: torch.Tensor) -> output_t:
    """Use the resident FP16 compact apply path from caller-staged FP16 state."""

    h = torch.empty(h16.shape, device=h16.device, dtype=torch.float32)
    batch, n, _ = h.shape
